const creds = $input.item.json;
const list = Array.isArray(creds) ? creds : [];
const now = Date.now();
const month = new Date().toISOString().slice(0, 7);
const alerts = [];

list.forEach(function (c) {
  if (!c.next_rotation_due) return;
  const dueAt = new Date(c.next_rotation_due).getTime();
  const daysToDue = Math.floor((dueAt - now) / 86400000);
  const warningDays = c.warning_threshold_days || 14;
  let severity = null;
  let title = null;
  if (daysToDue < 0) {
    severity = 'critical';
    title = '[' + c.credential_name + '] Rotation OVERDUE by ' + Math.abs(daysToDue) + ' day' + (Math.abs(daysToDue) === 1 ? '' : 's');
  } else if (daysToDue <= warningDays) {
    severity = 'warning';
    title = '[' + c.credential_name + '] Rotation due in ' + daysToDue + ' day' + (daysToDue === 1 ? '' : 's');
  } else {
    return;
  }
  alerts.push({
    severity: severity,
    alert_type: 'credential_rotation_due',
    title: title,
    message: 'Credential ' + c.credential_name + ' (' + c.credential_type + ', stored in ' + c.stored_in + ') reaches its ' + c.rotation_interval_days + '-day rotation interval on ' + c.next_rotation_due.slice(0,10) + '. After rotating, update sentinel_credential_inventory.last_rotated_at via the dashboard.',
    aggregation_key: 'credential_age:' + c.credential_name + ':' + month,
    details: { credential_name: c.credential_name, credential_type: c.credential_type, vendor: c.vendor, stored_in: c.stored_in, last_rotated_at: c.last_rotated_at, next_rotation_due: c.next_rotation_due, days_to_due: daysToDue, rotation_interval_days: c.rotation_interval_days, warning_threshold_days: warningDays }
  });
});

return { json: { alerts: alerts, credentials_checked: list.length } };

const alerts = $input.item.json.alerts || [];
if (!alerts.length) return [{ json: { _no_alerts: true } }];
return alerts.map(function (a) { return { json: a }; });
